18	@ApiTags('Health')
19	@Controller()
20	export class HealthController {
21		constructor(
22			private readonly health: HealthCheckService,
23			private readonly memory: MemoryHealthIndicator,
24			private readonly healthService: HealthService,
25		) {}
26	
27		@ApiOperation({ summary: 'Liveness probe' })
28		@ApiOkResponse({
29			description: 'Service is alive',
30			schema: {
31				type: 'object',
32				properties: { status: { type: 'string', enum: ['up'] } },
33			},
34		})
35		@Get('liveness')
36		isItUp(): { status: 'up' } {
37			return { status: 'up' };
38		}
39	
40		@ApiOperation({ summary: 'Readiness probe' })
41		@ApiResponse({
42			status: HttpStatus.OK,
43			description: 'Service is ready to serve traffic',
44		})
45		@HealthCheck()
46		@Get('readiness')
47		@LogExecution({ logResponse: false })
48		async isItWorking(): Promise<HealthCheckResult> {
49			if (isSIGTERM) {
50				return { status: 'shutting_down', info: {}, error: {}, details: {} };
51			}
52	
53			return await this.health.check([
54				() => this.healthService.isAppHealthy(),
55				() => this.memory.checkHeap('memory_heap', 500 * 1024 * 1024),
56			]);
57		}
58	}
