69	
70			if (!membership) {
71				throw new ForbiddenException('Not a member of this company');
72			}
73	
74			await this.sessionService.updateCompanyContext({
75				userId: user.user_id,
76				sessionId: user.session_id,
77				companyId: dto.company_id,
78				role: membership.role,
79			});
80	
81			return { success: true };
