39		@Public()
40		@Get('github')
41		@ApiOperation({ summary: 'Initiate GitHub OAuth' })
42		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to GitHub' })
43		@LogExecution({ logResponse: false })
44		async githubAuth(@Res() reply: FastifyReply): Promise<void> {
45			const url = await this.authService.initiateOAuth({ provider: 'github' });
46			reply.status(HttpStatus.FOUND).redirect(url.toString());
47		}
48	
49		@Public()
50		@Get('github/callback')
51		@ApiOperation({ summary: 'Handle GitHub OAuth callback' })
52		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
53		@LogExecution({ logParams: false, logResponse: false })
54		async githubCallback(
55			@Query('code') code: string,
56			@Query('state') state: string,
57			@Res() reply: FastifyReply,
58		): Promise<void> {
59			const result = await this.authService.handleCallback({
60				provider: 'github',
61				code,
62				state,
63			});
64			const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
65			if (result.type === 'auth_code') {
66				reply
67					.status(HttpStatus.FOUND)
68					.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
69			} else {
70				reply
71					.status(HttpStatus.FOUND)
72					.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
73			}
74		}
