113		@Public()
114		@Post('token')
115		@ApiOperation({ summary: 'Exchange auth code for JWT tokens' })
116		@ApiResponse({
117			status: HttpStatus.OK,
118			description: 'Returns access token, sets refresh cookie',
119		})
120		@LogExecution({ logParams: false, logResponse: false })
121		async exchangeToken(
122			@Body() dto: TokenExchangeDto,
123			@Req() request: FastifyRequest,
124			@Res() reply: FastifyReply,
125		): Promise<void> {
126			const result = await this.authService.exchangeCode({
127				code: dto.code,
128				ip: request.ip,
129				userAgent: request.headers['user-agent'] ?? '',
130				provider: 'github',
131			});
132	
133			reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
134				httpOnly: true,
135				secure: !isDevEnv(),
136				sameSite: 'strict',
137				path: '/api/auth',
138				maxAge: 30 * 24 * 60 * 60,
139			});
140	
141			reply.send({ access_token: result.accessToken });
142		}
