146		@Post('refresh')
147		@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
148		@ApiResponse({
149			status: HttpStatus.OK,
150			description: 'Returns new access token, rotates refresh cookie',
151		})
152		@ApiResponse({
153			status: HttpStatus.UNAUTHORIZED,
